mapper.select:
SELECT COALESCE(MAX(position), 0) + 1
FROM queues
WHERE queue_type = #{queueType}

SELECT queue_type
FROM queues
WHERE group_id = #{groupId}

mapper.update:
UPDATE queues q1
JOIN (
SELECT
queue_id,
ROW_NUMBER() OVER (ORDER BY position ASC, queue_id ASC) as new_position
FROM queues
WHERE queue_type = #{queueType}
) q2 ON q1.queue_id = q2.queue_id
SET q1.position = q2.new_position
WHERE q1.queue_type = #{queueType}
